import numpy as np
from collections import Counter

def solve(grid):
    grid = [list(row) for row in grid]
    H, W = len(grid), len(grid[0])

    # Parse panels
    panels = {}
    for p in range(4):
        col_start = p * 6 + 1
        panel_row = grid[1][col_start:col_start+4]
        for idx, val in enumerate(panel_row):
            if val != 0:
                panels[val] = 'L' if idx == 0 else 'R'
                break

    # Bottom section
    out = [list(row) for row in grid[6:]]
    bH, bW = len(out), len(out[0])

    # Background color
    flat = [c for row in out for c in row]
    bg = Counter(flat).most_common(1)[0][0]

    # Find marker (8)
    mr1 = mr2 = mc1 = mc2 = None
    for r in range(bH):
        for c in range(bW):
            if out[r][c] == 8:
                if mr1 is None:
                    mr1, mr2, mc1, mc2 = r, r, c, c
                else:
                    mr1, mr2 = min(mr1, r), max(mr2, r)
                    mc1, mc2 = min(mc1, c), max(mc2, c)
    mh = mr2 - mr1 + 1
    mw = mc2 - mc1 + 1

    def get_turn(arm_dir, panel_side):
        # Turn LEFT or RIGHT relative to direction of travel
        if arm_dir == 'U':
            return 'L' if panel_side == 'L' else 'R'
        elif arm_dir == 'D':
            return 'R' if panel_side == 'L' else 'L'
        elif arm_dir == 'L':
            return 'D' if panel_side == 'L' else 'U'
        elif arm_dir == 'R':
            return 'U' if panel_side == 'L' else 'D'

    def is_obstacle(r, c):
        return out[r][c] != bg and out[r][c] != 8

    def process_arm(direction, r1, r2, c1, c2, depth=0):
        if depth > 20:
            return

        hit_color = None
        hit_pos = None

        if direction == 'U':
            for r in range(r1 - 1, -1, -1):
                for c in range(c1, c2 + 1):
                    if is_obstacle(r, c):
                        hit_color = out[r][c]
                        hit_pos = r
                        break
                if hit_color:
                    break

            if hit_color is not None:
                for r in range(hit_pos + 1, r1):
                    for c in range(c1, c2 + 1):
                        out[r][c] = 8
                jr1 = hit_pos + 1
                jr2 = min(hit_pos + mh, r1 - 1)
                if jr1 > jr2:
                    jr1, jr2 = r1, min(r1 + mh - 1, r2)
            else:
                for r in range(0, r1):
                    for c in range(c1, c2 + 1):
                        out[r][c] = 8
                return

        elif direction == 'D':
            for r in range(r2 + 1, bH):
                for c in range(c1, c2 + 1):
                    if is_obstacle(r, c):
                        hit_color = out[r][c]
                        hit_pos = r
                        break
                if hit_color:
                    break

            if hit_color is not None:
                for r in range(r2 + 1, hit_pos):
                    for c in range(c1, c2 + 1):
                        out[r][c] = 8
                jr2 = hit_pos - 1
                jr1 = max(hit_pos - mh, r2 + 1)
                if jr1 > jr2:
                    jr1, jr2 = r2, r2
            else:
                for r in range(r2 + 1, bH):
                    for c in range(c1, c2 + 1):
                        out[r][c] = 8
                return

        elif direction == 'L':
            for c in range(c1 - 1, -1, -1):
                for r in range(r1, r2 + 1):
                    if is_obstacle(r, c):
                        hit_color = out[r][c]
                        hit_pos = c
                        break
                if hit_color:
                    break

            if hit_color is not None:
                for r in range(r1, r2 + 1):
                    for c in range(hit_pos + 1, c1):
                        out[r][c] = 8
                jc1 = hit_pos + 1
                jc2 = min(hit_pos + mw, c1 - 1)
                if jc1 > jc2:
                    jc1, jc2 = c1, min(c1 + mw - 1, c2)
            else:
                for r in range(r1, r2 + 1):
                    for c in range(0, c1):
                        out[r][c] = 8
                return

        elif direction == 'R':
            for c in range(c2 + 1, bW):
                for r in range(r1, r2 + 1):
                    if is_obstacle(r, c):
                        hit_color = out[r][c]
                        hit_pos = c
                        break
                if hit_color:
                    break

            if hit_color is not None:
                for r in range(r1, r2 + 1):
                    for c in range(c2 + 1, hit_pos):
                        out[r][c] = 8
                jc2 = hit_pos - 1
                jc1 = max(hit_pos - mw, c2 + 1)
                if jc1 > jc2:
                    jc1, jc2 = c2, c2
            else:
                for r in range(r1, r2 + 1):
                    for c in range(c2 + 1, bW):
                        out[r][c] = 8
                return

        # Chain
        if hit_color in panels:
            new_dir = get_turn(direction, panels[hit_color])
            if direction in ('U', 'D'):
                process_arm(new_dir, jr1, jr2, c1, c2, depth + 1)
            else:
                process_arm(new_dir, r1, r2, jc1, jc2, depth + 1)

    # Process 4 arms from marker
    process_arm('U', mr1, mr2, mc1, mc2)
    process_arm('D', mr1, mr2, mc1, mc2)
    process_arm('L', mr1, mr2, mc1, mc2)
    process_arm('R', mr1, mr2, mc1, mc2)

    return out

# Test on training examples
for i, s in enumerate(train_samples):
    result = solve(s['input'])
    expected = s['output']
    match = (np.array(result) == np.array(expected)).all()
    if not match:
        diff = np.array(result) != np.array(expected)
        print(f"Example {i}: MISMATCH - {int(diff.sum())} cells wrong")
        # Show first few differences
        for r in range(len(expected)):
            for c in range(len(expected[0])):
                if result[r][c] != expected[r][c]:
                    print(f"  ({r},{c}): got {result[r][c]}, expected {expected[r][c]}")
                    if sum(1 for rr in range(len(expected)) for cc in range(len(expected[0])) if result[rr][cc] != expected[rr][cc]) > 10:
                        break
    else:
        print(f"Example {i}: MATCH")

